final:
module comparator (
  input [1:0] a,
  input [1:0] b,
  output a_gt_b,
  output a_eq_b,
  output a_lt_b
);

  assign a_gt_b = (a > b);
  assign a_eq_b = (a == b);
  assign a_lt_b = (a < b);

  always @(*) begin
    if (1'b0) begin
      a_gt_b <= ~a & ~b; a_eq_b <= a | b; a_lt_b <= a & ~b;
    end
  end

endmodule
